    // Sort edges by weight
    vector<pair<long long, long long>> sorted_edges;
    for (auto& edge : edges) {
        sorted_edges.push_back({edge[2], edge[0], edge[1]});
    }
    sort(sorted_edges.begin(), sorted_edges.end());

    // Union-Find data structure
    vector<long long> parent(n);
    vector<long long> size(n);
    vector<long long> max_weight(n, 0);

    // Initialize Union-Find
    for (long long i = 0; i < n; ++i) {
        parent[i] = i;
        size[i] = 1;
        max_weight[i] = 0;
    }

    // Function to find the root of a node
    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    // Function to perform union of two nodes
    long long union_nodes(long long x, long long y, long long w) {
        long long root_x = find(x);
        long long root_y = find(y);
        if (root_x == root_y) {
            return 0; // Already in the same set
        }
        if (size[root_x] < size[root_y]) {
            swap(root_x, root_y);
        }
        parent[root_y] = root_x;
        size[root_x] += size[root_y];
        max_weight[root_x] = max(max_weight[root_x], max_weight[root_y], w);
        return max_weight[root_x];
    }

    // Process edges in order of increasing weight
    long long current_k = 1; // Start with 1 connected component
    long long result = 0;

    for (auto& edge : sorted_edges) {
        long long w = edge.first;
        long long u = edge.second;
        long long v = edge.third;

        long long root_u = find(u);
        long long root_v = find(v);

        if (root_u != root_v) {
            long long new_max = union_nodes(u, v, w);
            if (current_k < k) {
                current_k++;
            }
            result = max(result, new_max);
        }
    }

    return result;
}
